INSERT INTO public.interactions VALUES ('c52726d0-8eb7-46eb-ac77-7193e9d2ac19', 'd80430f2-8885-4a08-b0b4-fd697034ab98', 'sales', 'Call', 'Melanie wants to know when Evolve x 3 with old labels will be collected and why cant she add stickers as baby Bjorn are doing .  She said all other suppliers have added stickers to remaining stock.     Ive explained we dont believe its a good solution, as stickers can be removed.  I apologies for the wait and that Im waiting for JQ  to let me know plan for collection.', '2026-01-22 00:42:36.912', NULL, NULL, NULL, '2026-01-20 16:00:00', NULL);
INSERT INTO public.interactions VALUES ('2149cd4b-ffaf-4153-9cac-9c4b6823d42e', '077cc32d-b790-4803-a2d3-94db580d4f67', 'sales', 'Call', 'CJ called to as if she can sell an Evolve waiting to be collected after cut off,  I said not really  but up to them to make the choice.  Waiting for JQ  to let them know what the plan is.', '2026-01-19 16:00:00', NULL, NULL, NULL, '2026-01-19 16:00:00', NULL);
INSERT INTO public.interactions VALUES ('48d98e42-897d-4e85-ba98-32d5aa3973e0', '077cc32d-b790-4803-a2d3-94db580d4f67', 'sales', 'Call', 'Jo called,  had a big chat about their plans for the year,  they want more exclusivity, ( like Dorrell gives them with Maxi cosi) We will plan a date to go down and discuss plans for the year to grow Ergo and Skip Hop and Bubble,  I explained their sales with us had dropped 50% last year. will wiat for Ania to retrna nd Jamie and discuss a plan to visit mid to late feb.', '2026-01-22 01:41:31.011931', NULL, NULL, NULL, '2026-01-21 16:00:00', NULL);
INSERT INTO public.interactions VALUES ('a21d1f1c-6568-4145-9a0f-b885322bab4d', 'b04e3e33-5183-4191-af6b-30397bd16921', 'sales', 'Call', 'Call follow up Sunway Carnival movement', '2026-01-22 02:23:21.406938', NULL, NULL, NULL, '2026-01-21 16:00:00', NULL);
INSERT INTO public.interactions VALUES ('b13997b3-3df7-4bfa-adba-4ea45001b652', '16c844a2-46e0-4e8e-92ad-73e5af3b8fce', 'sales', 'Call', 'Contacted customer to arrange a physical meeting to discuss on how we can collab even closer and better for 2026. Also reviewed customer website to ensure retailer is well stocked. Realised they havent stock up on certain new skus (new colour for ergo) and certain existing skus are OOS on their website but our TX has arrived and back in stock.', '2026-01-23 01:46:39.010258', NULL, NULL, NULL, '2026-01-22 16:00:00', NULL);
